import { readFileSync, writeFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const rulesPath = resolve(__dirname, '..', 'rules', 'AGENTS.md');

const content = readFileSync(rulesPath, 'utf-8');
const escaped = content.replace(/\\/g, '\\\\').replace(/`/g, '\\`').replace(/\${/g, '\\${');

const output = `// This file is auto-generated by scripts/build-rules.ts
// Do not edit manually — edit rules/AGENTS.md instead.

export const RULES_CONTENT: string = \`${escaped}\`;
`;

const outPath = resolve(__dirname, '..', 'src', 'rules-content.ts');
writeFileSync(outPath, output, 'utf-8');
